SELECT o.id AS order_id , o.code AS order_code , CASE WHEN COUNT(DISTINCT po.product_id) > 1 THEN CONCAT(MIN(p.name), ' 외 ', COUNT(DISTINCT po.product_id) - 1, '건') ELSE MIN(p.name) END AS product_summary , o.status , o.created_at , o.total_amount , f.name AS franchise_name FROM orders o JOIN franchise f ON o.franchise_id = f.id LEFT JOIN hq_user_detail h ON f.department_id = h.department_id JOIN product_order po ON o.id = po.order_id JOIN product p ON po.product_id = p.id
o.status NOT IN ('WAITING_FOR_RECEIPT', 'RECEIPT_CANCELED')
AND o.status = #{status}
AND h.user_id = #{userId}
AND o.franchise_id = #{franchiseId}
AND o.code LIKE CONCAT('%', #{code}, '%')
AND EXISTS ( SELECT 1 FROM product_order po2 JOIN product p2 ON po2.product_id = p2.id WHERE po2.order_id = o.id AND p2.name LIKE CONCAT('%', #{product}, '%') )
AND DATE(o.created_at) BETWEEN #{startDate} AND #{endDate}
GROUP BY o.id, o.code, o.status, o.created_at, o.total_amount, f.name ORDER BY o.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(DISTINCT o.id)
  FROM orders o
  JOIN franchise f ON o.franchise_id = f.id
  JOIN hq_user_detail h ON f.department_id = h.department_id


    o.status NOT IN ('WAITING_FOR_RECEIPT', 'RECEIPT_CANCELED')


        AND o.status = #{status}



        AND h.user_id = #{userId}



        AND o.franchise_id = #{franchiseId}



        AND o.code LIKE CONCAT('%', #{code}, '%')



        AND EXISTS (
        SELECT 1 FROM product_order po
        JOIN product p ON po.product_id = p.id
        WHERE po.order_id = o.id
        AND p.name LIKE CONCAT('%', #{product}, '%')
        )



        AND DATE(o.created_at) BETWEEN #{startDate} AND #{endDate}
